// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.0;

import {Errors} from "src/libraries/Errors.sol";

/// @title Caller Contract.
/// @notice This abstract contract provides functionality to perform low-level calls to other contracts and handle
/// errors
abstract contract Caller {
  error LowLevelCallFailed();

  struct Call {
    address target; // The address to be called.
    bytes data; // The lowlevel call data.
  }

  /// @notice Perfoms a low-level call to a target address with the provided data and bubbles up revert messages.
  /// @param target The address to call.
  /// @param data The call data to send to the target.
  /// @return returnData The data returned from the call.
  function _call(
    address target,
    bytes memory data
  ) internal returns (bytes memory returnData) {
    // If the caller has specified data.
    // solhint-disable-next-line avoid-low-level-calls
    (bool success, bytes memory response) = target.call(data);

    // Check if the call was successful or not.
    if (!success) {
      // If there is return data, the call reverted with a reason or a custom error, which we bubble up.
      if (response.length > 0) {
        assembly {
          // The length of the data is at `response`, while the actual data is at `response + 32`.
          let returndataSize := mload(response)
          revert(add(response, 32), returndataSize)
        }
      } else {
        revert LowLevelCallFailed();
      }
    }

    return response;
  }

  /// @notice Performs multiple low-level calls to target addresses with the provided data.
  /// @param calls An array of Call structs containing target addresses and call data.
  /// @return returnData An array of bytes containing the data returned from each call.
  function _multiCall(
    Call[] memory calls
  ) internal returns (bytes[] memory) {
    if (calls.length == 0) {
      revert Errors.EmptyList();
    }

    bytes[] memory returnData = new bytes[](calls.length);

    for (uint256 i = 0; i < calls.length; ++i) {
      returnData[i] = _call(calls[i].target, calls[i].data);
    }

    return returnData;
  }
}

// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.0;

interface IAuctionCallback {
  /// @notice The auction callback function which executes the solving logic.
  /// @param from The address of the caller of the auction contract's bid function.
  /// @param asset The address of the asset being auctioned.
  /// @param amountOut The amount of asset's being sold to the auction.
  /// @param data The auction callback data originally passed from the bid function.
  function auctionCallback(
    address from,
    address asset,
    uint256 amountOut,
    bytes calldata data
  ) external;
}

// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.0;

interface IBaseAuction {
  /// @notice method that is simulated by auction manager to see if any work actually
  /// needs to be performed.
  /// @param checkData Unused parameter, only for CLA backward compatibility.
  /// @return upkeepNeeded boolean to indicate whether the auction manager should call
  /// performUpkeep or not.
  /// @return performData bytes that the workflow should call performUpkeep with, if
  /// upkeep is needed. If you would like to encode data to decode later, try
  /// `abi.encode`.
  function checkUpkeep(
    bytes calldata checkData
  ) external returns (bool upkeepNeeded, bytes memory performData);

  /// @notice method that is actually executed by the auction manager.
  /// The data returned by the checkUpkeep simulation will be passed into
  /// this method to actually be executed.
  /// @param performData is the data which was passed back from the checkData
  /// simulation. If it is encoded, it can easily be decoded into other types by
  /// calling `abi.decode`. This data should not be trusted, and should be
  /// validated against the contract's current state.
  function performUpkeep(
    bytes calldata performData
  ) external;

  /// @notice Allows a user to bid in an active auction for a specific asset.
  /// @param asset The address of the asset being auctioned.
  /// @param amount The amount of the asset being auctioned.
  /// @param data The optional data to be sent to the receiver as part of the callback
  function bid(
    address asset,
    uint256 amount,
    bytes calldata data
  ) external;

  /// @notice Getter function to retrieve the asset out address.
  /// @return assetOut The address of the asset out.
  function getAssetOut() external view returns (address assetOut);

  // @notice Getter function to compute the current auction price for a given asset and amount at a specific timestamp.
  /// @param assetIn The address of the asset.
